INSERT INTO `Oficio_tipo` (`ID_TipOficio`, `Nombre`, `Parrafo1`, `Parrafo2`, `Parrafo3`, `Parrafo4`) VALUES
(1, 'OFICIO DE ASIGNACION DE NOMENCLATURA Y VALUACION DEL PREDIO FUNDO LEGAL', '{{__REGULAR__}}En atención a su solicitud de fecha {{FechaSolicitud}}, para valorizar y asignar nomenclatura a un lote del fundo legal ubicado en la calle {{Direccion}} con cruzamientos {{Cruzamientos}} de la localidad y municipio de {{Municipio}}, Yucatán; con {{Frente}} metros de frente por {{Fondo}} metros de fondo, mismo que será asignado para \"casa habitación\" al C. {{Propietarios}}, a continuación, me permito dar a conocer la siguiente información que se requiere:', '{{__IIIREGULAR__}}En atención a su solicitud de fecha {{FechaSolicitud}}, para valorizar y asignar nomenclatura a un lote del fundo legal ubicado en la calle {{Direccion}} con cruzamientos {{Cruzamientos}} de la localidad y municipio de {{Municipio}}, Yucatán; con {{Frente}} metros de frente por {{Fondo}} metros de fondo en su mayor extension; de figura irregular, mismo que será asignado para \"casa habitación\" al C. {{Propietarios}}, a continuación, me permito dar a conocer la siguiente información que se requiere:', 'Cumpliendo lo dispuesto en el artículo 127 fracción XXXI del reglamento de ley que crea el instituto de seguridad jurídica patrimonial de Yucatán, articulo 20 fracciones lll y Xl y 24 fracciones l y Vl del Estatuto Orgánico del instituto de Seguridad Jurídica Patrimonial de Yucatán.', 'Con fundamento en los Artículos 1, 148, 169 de la Ley que crea el Instituto de Seguridad Jurídica Patrimonial de Yucatán, 127 Fracción VIII del Reglamento de la Ley que crea el Instituto de Seguridad Jurídica Patrimonial.'),
(2, 'OFICIO DE DIVISION DE PREDIOS', '{{__URBANO__}}En contestación a su solicitud y verificadas las dimensiones de las partes en que se dividirá el predio Urbano ubicado en la Manzana {{Manzana}} de la Sección catastral {{Seccion}} marcado con el número {{Numero}} ({{NumLetras}}) de la calle {{Direccion}} ({{NumLetrasDireccion}}) de la localidad y municipio de {{Municipio}}, Yucatán, Los avalúos catastrales quedan como se describe a continuacion en la siguente tabla de valores:', '{{__RUSTICO__}}En contestación a su solicitud y verificadas las dimensiones de las partes en que se dividirá el predio rustico marcado con el número de tablaje catastral {{NumTablaje}} ({{NumLetras}}) ubicado en la localidad de {{Municipio}}, Yucatán; los avalúos catastrales son como siguen:', 'Los datos contenidos en el presente oficio solo surtirán efectos de registro en esta dirección cumpliendo lo dispuesto en el Artículo 130 del Reglamento de la Ley que crea el Instituto de Seguridad Jurídica Patrimonial de Yucatán, en los términos establecidos en el Artículo 154 de la propia Ley en vigor.', 'Con fundamento en los Artículos 1, 148, 169 de la Ley que crea el Instituto de Seguridad Jurídica Patrimonial de Yucatán, 127 Fracción VIII del Reglamento de la Ley que crea el Instituto de Seguridad Jurídica Patrimonial.'),
(3, 'OFICIO DE RECTIFICACION DE MEDIDAS', '{{__URBANO__}}En contestación a su solicitud y verificadas las dimensiones de los datos del predio urbano ubicado en la Manzana {{Manzana}} de la Sección catastral {{Seccion}} marcado con el número {{Numero}} ({{NumLetras}}) de la calle {{Direccion}} ({{NumLetrasDireccion}}) de la localidad y municipio de {{Municipio}}, Yucatán, que tenía {{Frente}} metros de frente y {{Fondo}} metros de fondo. Y una superficie de {{Area}} M2 quedará con las cualidades siguientes, y previa Rectificación de Medidas autorizadas por el personal a cargo del departamento de catastro.', '{{__RUSTICO__}}En contestación a su solicitud y verificadas las dimensiones de los datos del Tablaje Catastral, marcado con el número {{Tablaje}} ({{TablajeLetras}})  uubicado en la localidad y municipio de {{Municipio}}, Yucatán; que tenía {{Frente}} metros de frente y {{Fondo}} metros de fondo. Y una superficie de {{Area}} M2 quedará con las cualidades siguientes, y previa Rectificación de Medidas autorizadas por el personal a cargo del departamento de catastro.', 'Los datos contenidos en el presente oficio solo surtirán efectos de registro en esta dirección cumpliendo lo dispuesto en el Artículo 130 del Reglamento de la Ley que crea el Instituto de Seguridad Jurídica Patrimonial de Yucatán, en los términos establecidos en el Artículo 154 de la propia Ley en vigor.', 'Con fundamento en los Artículos 1, 148, 169 de la Ley que crea el Instituto de Seguridad Jurídica Patrimonial de Yucatán, 127 Fracción VIII del Reglamento de la Ley que crea el Instituto de Seguridad Jurídica Patrimonial.'),
(4, 'Libre', '', '', '', ''),
(5, 'OFICIO DE CAMBIO DE NOMECLATURA', 'Por medio de la presente nos permitimos informar a usted que de acuerdo a su solicitud y a los antecedentes que existen en los archivos de ésta Dirección,  el predio {{Tipo}} marcado con el numero {{Numero}}, ubicado en la localidad y municipio de {{Municipio}}, Yucatán, inscrito con el número de inscripción {{inscripción}} en el Registro Público de la Propiedad y del Comercio del Instituto de Seguridad Jurídica Patrimonial de Yucatán, POR CAMBIO DE NOMENCLATURA pasó a ser el {{PredioTab}} número {{nuevo}}  ubicado en la Localidad y Municipio de {{Municipio}}, Yucatán; a partir de la fecha de emisión de la Cédula Catastral por Cambio de Nomenclatura con folio {{FolioCedula}} de fecha {{FechaCedula}}.', '', 'Los datos contenidos en el presente oficio solo surtirá efectos de registro en esta dirección cuando éstos hayan sido inscritos en el Registro Público de la Propiedad y del Comercio del Instituto de Seguridad Jurídica Patrimonial de Yucatán, en los términos establecidos en el artículo 154 de la Ley que crea el Instituto de Seguridad Jurídica Patrimonial de Yucatán', 'Con fundamento en los artículos 2 fracciones I y II, 6 de la Ley de Actos y Procedimientos Administrativos del Estado de Yucatán, 1, 2, 4 y 66 fracción I del código de la Administración Publica de Yucatán, 1, 124 fracción XIII de la ley que crea el Instituto de Seguridad Jurídica Patrimonial de Yucatán, 20 fracciones III y XI y 24 fracción I del Estatuto Orgánico del Instituto de Seguridad Jurídica Patrimonial de Yucatán.'),
(6, 'ACTA CIRCUNSTANCIADA', 'La que suscribe {{Director}}, Director(a) del Catastro del municipio de {{Municipio}}, Yucatán, me dirijo a Usted con el debido respeto que se merece y que en relación a lo solicitado del señor {{Propietarios}}, con el fin de rendir el informe respecto del predio {{Tipo}} marcado con el {{TabOrNum}} {{Numero}} ({{NumLetras}}) de esta localidad y municipio de {{Municipio}}, Yucatán.', 'Que dicho predio se halla inscrito en las oficinas del catastro de {{Municipio}}, Yucatán a nombre del señor {{Propietarios}}, y que previamente fue verificado por personal correspondiente de la direccion de catastro municipal, encontrándose presentes en ese momento los colindantes quienes manifestaron ser legítimos propietarios de dichos inmuebles aledaños; como sigue:', 'De la diligencia de verificación llevada a cabo se obtuvo que el predio no cuenta con las medidas exactas que obran inscritas en el Registro Público de la Propiedad con folio electrónico {{FolioElectronico}}, y por tal motivo es susceptible de llevar un proceso de rectificación de medidas. Motivo por el cual se les explica y hace de su conocimiento a cada uno de los propietarios colindantes que dicho predio se rectificara, ya que no afecta ningún predio colindante de los señalados anteriormente, toda vez que cada uno de ellos señalo donde empieza y termina su predio.', 'Se hace constar que el objeto de la presente inspección es de carácter administrativo de acuerdo a lo siguiente: Será aprobado el proyecto de rectificación de medidas solicitado por el C. {{Propietarios}}, ya que no afecta al predio de la C. {{Destinatario}}, colindante del lado {{Lado}}, la cual accedió que se verifique su predio señalando donde empieza y termina su predio, pero se negó a firmar. Se expide la presente acta a petición de la parte interesada, para los fines que corresponda, a los {{FechaEscrita}}.'),
(7, 'OFICIO DE UNION DE PREDIOS', 'En contestación a su solicitud y verificadas las dimensiones de las partes en que se unirán los predios {{Clase}} ubicados en la Sección {{Seccion}}, Manzana {{Manzana}}, marcado con el número {{NumeroOrig}} ({{NumLetraPredioOrig}}) de la calle {{DireccionOrig}} ({{NumLetraDirOrig}}) con el predio marcado con el número {{NumPredioMerg}} ({{NumLetraPredioMerg}}) de la calle {{DirPredioMerg}} ({{NumLetraDirMerg}}), de la Localidad y Municipio de {{Municipio}}, Yucatán, el avalúo catastral es como sigue:', 'En contestación a su solicitud y verificadas las dimensiones de las partes en que se unirán los predios {{Clase}} marcados con los números de tablaje {{NumeroOrig}} ({{NumLetraPredioOrig}}) con el tablaje marcado con el número {{NumPredioMerg}} ({{NumLetraPredioMerg}}), de la Localidad y Municipio de {{Municipio}}, Yucatán, el avalúo catastral es como sigue:', 'Solo surtirá efectos de registro en esta dirección cumpliendo lo dispuesto en el Artículo 130 del Reglamento de la ley que crea el Instituto de Seguridad Jurídica Patrimonial de Yucatán, en los términos establecidos en el artículo 154 de la propia Ley en vigor.', ''),
(8, 'OFICIO DE URBANIZACION', 'En contestación a su solicitud y verificadas las dimensiones del predio {{Clase}} número {{Numero}} ({{NumLetra}}), de la localidad y Municipio de {{Municipio}}, Yucatán, el cual se urbanizará, formando el predio Urbano Número {{NewNumero}} ({{NumLetraNew}}), de la calle {{Direccion}} ({{NumLetraDir}}) que se ubica en la Sección Catastral {{Seccion}} Manzana {{Manzana}}, de esta misma localidad, con los avalúos catastrales siguientes:', '', 'Solo surtirá efectos de registro en esta dirección cumpliendo lo dispuesto en el Art. 4 transitorio del reglamento de la ley de catastro en vigor.', '');
